{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/AnnotationRuleArrayAnnotationTest.kt","content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class AnnotationRuleArrayAnnotationTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given array-style annotation on same line as annotated construct`() {
        val code =
            """
            @[Foo Bar] class Foo
            """.trimIndent()
        val formattedCode =
            """
            @[Foo Bar]
            class Foo
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolation(1, 1, "Annotation must be placed on separate line")
            .isFormattedAs(formattedCode)
    }
}
"}

